interface SystemClock {
    LocalDateTime now();
}

class WallClock implements SystemClock {
    public LocalDateTime now() {
        return LocalDateTime.now();
    }
}

// Used in production code; FakeClock used in tests
class SubscriptionExpiryChecker {
    private final SystemClock clock;

    SubscriptionExpiryChecker(SystemClock clock) {
        this.clock = clock;
    }

    boolean hasSubscriptionExpired(Subscription subscription) {
        return subscription.getExpiryDate().isBefore(clock.now().toLocalDate());
    }
}
